import React, { useEffect, useState } from 'react';

interface HomeProps {
  navigate: (page: string) => void;
}

const cards = [
  { icon: '👤', label: 'About Me',        page: 'about',      desc: 'Who I am & my story'         },
  { icon: '💼', label: 'Experience',       page: 'experience', desc: '4 roles across NZ'            },
  { icon: '🎓', label: 'Skills & Certs',   page: 'skills',     desc: 'Cloud, Security & more'       },
  { icon: '✉️', label: 'Contact',          page: 'contact',    desc: 'Get in touch with me'         },
];

const tags = ['AWS', 'Azure AZ-104', 'ISC2 CC', 'Intune', 'SCCM', 'Microsoft 365', 'PowerShell', 'Defender'];

const Home: React.FC<HomeProps> = ({ navigate }) => {
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const t = setTimeout(() => setVisible(true), 80);
    return () => clearTimeout(t);
  }, []);

  return (
    <div style={{
      height: '100%',
      display: 'flex',
      flexDirection: 'column',
      background: '#fff',
      opacity: visible ? 1 : 0,
      transition: 'opacity 0.4s ease',
      overflowY: 'auto',
    }}>

      {/* Hero banner */}
      <div style={{
        background: 'linear-gradient(135deg, #000080 0%, #1084d0 100%)',
        color: '#fff',
        padding: '48px 48px 40px',
        position: 'relative',
        overflow: 'hidden',
      }}>
        {/* Subtle grid pattern */}
        <div style={{
          position: 'absolute', inset: 0, opacity: 0.06,
          backgroundImage: 'repeating-linear-gradient(0deg,#fff 0,#fff 1px,transparent 1px,transparent 32px),repeating-linear-gradient(90deg,#fff 0,#fff 1px,transparent 1px,transparent 32px)',
        }} />

        <div style={{ position: 'relative' }}>
          <div style={{
            display: 'inline-block',
            background: 'rgba(255,255,255,0.15)',
            border: '1px solid rgba(255,255,255,0.3)',
            padding: '3px 12px',
            fontSize: 11,
            letterSpacing: 2,
            textTransform: 'uppercase',
            marginBottom: 16,
          }}>
            Digital Experience Partner
          </div>

          <h1 style={{
            fontSize: 52,
            fontFamily: 'Georgia, serif',
            fontWeight: 'bold',
            lineHeight: 1.1,
            marginBottom: 12,
            textShadow: '0 2px 8px rgba(0,0,0,0.3)',
          }}>
            Raghv Bhatia
          </h1>

          <p style={{
            fontSize: 14,
            opacity: 0.9,
            maxWidth: 520,
            lineHeight: 1.7,
            marginBottom: 28,
          }}>
            IT professional based in New Zealand — solving technical challenges across
            cloud platforms, endpoint management, and cybersecurity. Currently at
            <strong> Farmlands Co-operative Ltd</strong>.
          </p>

          {/* Tag chips */}
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
            {tags.map(t => (
              <span key={t} style={{
                padding: '3px 10px',
                background: 'rgba(255,255,255,0.18)',
                border: '1px solid rgba(255,255,255,0.35)',
                fontSize: 11,
                borderRadius: 2,
              }}>{t}</span>
            ))}
          </div>
        </div>
      </div>

      {/* Nav cards */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(2, 1fr)',
        gap: 1,
        background: '#c0c0c0',
        flex: 1,
      }}>
        {cards.map(card => (
          <div
            key={card.page}
            onClick={() => navigate(card.page)}
            style={{
              background: '#fff',
              padding: '28px 32px',
              cursor: 'pointer',
              display: 'flex',
              alignItems: 'flex-start',
              gap: 16,
              transition: 'background 0.15s',
            }}
            onMouseEnter={e => (e.currentTarget.style.background = '#f0f4ff')}
            onMouseLeave={e => (e.currentTarget.style.background = '#fff')}
          >
            <span style={{ fontSize: 28, lineHeight: 1, flexShrink: 0 }}>{card.icon}</span>
            <div>
              <div style={{ fontWeight: 'bold', fontSize: 13, marginBottom: 4, color: '#000080' }}>
                {card.label}
              </div>
              <div style={{ fontSize: 11, color: '#666' }}>{card.desc}</div>
            </div>
            <span style={{ marginLeft: 'auto', color: '#aaa', fontSize: 16, alignSelf: 'center' }}>›</span>
          </div>
        ))}
      </div>

    </div>
  );
};

export default Home;
